mapper.select:
SELECT tenant_id
FROM account_tenant_access
WHERE account_id = #{id}

mapper.update:
UPDATE account_tenant_access
SET account_id = #{accountId},
    tenant_id = #{tenantId},
    updated_at = NOW()
WHERE account_id = #{accountId}
  AND tenant_id = #{tenantId}

update account
set status = #{status}
where id = #{id}

mapper.delete:
DELETE FROM account
WHERE id = #{id}
  AND status = #{status}

DELETE FROM account_tenant_access
WHERE account_id = #{accountId}
  AND tenant_id = #{tenantId}

DELETE FROM account_link
WHERE id = #{id}
  AND tenant_id = #{tenantId}

DELETE FROM account_link
WHERE tenant_id = #{tenantId}
  AND (account_id_1 = #{accountId} OR account_id_2 = #{accountId})

DELETE FROM account_link
WHERE tenant_id = #{tenantId}
  AND account_id_1 = #{accountId1}
  AND account_id_2 = #{accountId2}

mapper.select:
SELECT * FROM account_link
WHERE tenant_id = #{tenantId}
  AND (account_id_1 = #{accountId} OR account_id_2 = #{accountId})

SELECT * FROM account_link
WHERE tenant_id = #{tenantId}
  AND account_id_1 = #{accountId1}
  AND account_id_2 = #{accountId2}
